import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent {
  // بيانات قسم الخدمات (Our Services)
  services = [
    { title: 'PEDIATRICIANS', image: 'assets/service1.jpg' },
    { title: 'BRAIN SURGEONS', image: 'assets/service2.jpg' },
    { title: 'IMMUNOLOGISTS', image: 'assets/service3.jpg' }
  ];

  // بيانات قسم الأطباء (Our Doctors) - مصفوفة مكررة لـ 12 طبيبًا لتطابق الشبكة في التصميم
  doctors = Array(12).fill({
    name: "Doctor's Name",
    specialty: 'Specialty',
    image: 'assets/doctor-avatar.jpg'
  });

  // نموذج إرسال الرسائل (Send us a message)
  contactData = {
    firstName: '',
    lastName: '',
    mobileNumber: '',
    email: '',
    message: ''
  };

  onSubmit() {
    console.log('Form Submitted Successfully!', this.contactData);
    // هنا يتم ربط كود الـ Service لإرسال البيانات للـ API أو الـ Backend لاحقاً
  }
}
